export function validateContentLength(content) {
    const plainText = content
        .replace(/\[IMAGE:.*?\]/g, '')
        .replace(/!\[.*?\]\(.*?\)/g, '')
        .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
        .replace(/[#*`]/g, '')
        .replace(/\s/g, '');
    const length = plainText.length;
    if (length > 2000) {
        return {
            valid: false,
            length,
            message: `❌ 글자수 초과: ${length}자 (최대 2000자)`,
            severity: 'error'
        };
    }
    if (length < 500) {
        return {
            valid: false,
            length,
            message: `❌ 너무 짧음: ${length}자 (최소 500자)`,
            severity: 'error'
        };
    }
    return {
        valid: true,
        length,
        message: `✅ 적절: ${length}자`
    };
}
export function validateImageCount(content) {
    const imageMatches = content.match(/\[IMAGE:.*?\]/g) || [];
    const count = imageMatches.length;
    if (count > 0) {
        return {
            valid: false,
            count,
            message: `❌ 이미지 불필요: ${count}개 감지`
        };
    }
    return {
        valid: true,
        count: 0,
        message: '✅ 이미지 없음'
    };
}
